class Solution:
    def minDifference(self, nums, queries):
        ans = []
        for l, r in queries:
            present = sorted(set(nums[l:r + 1]))
            if len(present) < 2:
                ans.append(-1)
            else:
                best = min(present[i + 1] - present[i] for i in range(len(present) - 1))
                ans.append(best)
        return ans

