class Solution:
    def minDifference(self, nums, queries):
        MAXV = 100
        n = len(nums)
        prefix = [[0] * (MAXV + 1) for _ in range(n + 1)]
        for i in range(n):
            row = prefix[i + 1]
            prev = prefix[i]
            for v in range(1, MAXV + 1):
                row[v] = prev[v]
            row[nums[i]] += 1
        ans = []
        for l, r in queries:
            pl, pr = prefix[l], prefix[r + 1]
            last = -1
            best = float('inf')
            for v in range(1, MAXV + 1):
                if pr[v] - pl[v] > 0:
                    if last != -1 and v - last < best:
                        best = v - last
                    last = v
            ans.append(-1 if best == float('inf') else best)
        return ans

