var minDifference = function(nums, queries) {
    const MAXV = 100;
    const n = nums.length;
    const prefix = Array.from({length: n + 1}, () => new Int32Array(MAXV + 1));
    for (let i = 0; i < n; i++) {
        const row = prefix[i + 1];
        const prev = prefix[i];
        for (let v = 1; v <= MAXV; v++) row[v] = prev[v];
        row[nums[i]] += 1;
    }
    const ans = [];
    for (const [l, r] of queries) {
        const pl = prefix[l], pr = prefix[r + 1];
        let last = -1, best = Infinity;
        for (let v = 1; v <= MAXV; v++) {
            if (pr[v] - pl[v] > 0) {
                if (last !== -1 && v - last < best) best = v - last;
                last = v;
            }
        }
        ans.push(best === Infinity ? -1 : best);
    }
    return ans;
};
